-- seed_community_posts.sql — 콜드스타트 마중물 게시글(전부 익명 author_id=null).
-- 역할별 QnA: free=손님(메뉴추천·동네질문) / staff=직장인(업무 감정토로·공감) / owner=사장님(창업·운영 조언질문). 가짜 업체명 없음.
-- ⚠️ Supabase SQL Editor 붙여넣고 Run. 중복방지 가드 있음(두 번 돌려도 안 겹침).
-- 정리(시드만 삭제): delete from public.posts where author_id is null;   (실유저 글은 author_id 있어 안 지워짐)
do $$
begin
  if (select count(*) from public.posts where author_id is null) > 0 then
    raise notice '이미 시드 글이 있어 건너뜀. 다시 넣으려면 먼저 delete from public.posts where author_id is null;';
    return;
  end if;
  raise notice '시드 게시글 50개 추가 완료.';
end $$;
