  insert into public.posts (board, dong, title, body, body_preview, anonymous, author_id, like_count, created_at) values
    ('free','석사동','비 오는 날엔 역시 국물','오늘같이 흐린 날 뜨끈한 국물 땡기는데 뭐가 좋을까요? 칼국수랑 짬뽕 사이에서 30분째 고민 중... 🍜 결정 좀 대신 해주세요 ㅠㅠ','오늘같이 흐린 날 뜨끈한 국물 땡기는데 뭐가 좋을까요? 칼국수랑 짬뽕 사이에서 30분째 고민 중... 🍜 결정 좀 대신 해주세요 ㅠㅠ', true, null, floor(random()*14)::int, now() - (random()*14*86400 || ' seconds')::interval),
    ('free','후평동','혼밥 메뉴 추천좀','요즘 혼자 먹을 일이 많은데 혼밥하기 편한 메뉴 뭐 있을까요. 국밥이나 덮밥 정도밖에 안 떠오르네요. 다들 혼자 뭐 드세요?','요즘 혼자 먹을 일이 많은데 혼밥하기 편한 메뉴 뭐 있을까요. 국밥이나 덮밥 정도밖에 안 떠오르네요. 다들 혼자 뭐 드세요?', true, null, floor(random()*14)::int, now() - (random()*14*86400 || ' seconds')::interval),
    ('free','퇴계동','요즘 배달 뭐 시켜드세요?','매번 시키던 것만 시키니까 질려서요 😅 최근에 시켰는데 의외로 맛있었던 메뉴 있으면 공유 좀 해주세요. 지금 배 고파서 아무거나 다 맛있어 보임 ㅋㅋ','매번 시키던 것만 시키니까 질려서요 😅 최근에 시켰는데 의외로 맛있었던 메뉴 있으면 공유 좀 해주세요. 지금 배 고파서 아무거나 다 맛있어 보임 ㅋㅋ', true, null, floor(random()*14)::int, now() - (random()*14*86400 || ' seconds')::interval),
    ('free','효자동','디저트 땡긴다','갑자기 단 거 폭발할 것 같은데 🍰 요즘 뭐가 맛있나요. 케이크 말고 색다른 디저트도 추천받아요.','갑자기 단 거 폭발할 것 같은데 🍰 요즘 뭐가 맛있나요. 케이크 말고 색다른 디저트도 추천받아요.', true, null, floor(random()*14)::int, now() - (random()*14*86400 || ' seconds')::interval),
    ('free','온의동','야식 뭐 먹지 다들','밤 열한시에 배고파서 잠이 안 온다... 살찌는 거 알지만 오늘만 좀 봐주기로 함. 야식 뭐가 좋을까요','밤 열한시에 배고파서 잠이 안 온다... 살찌는 거 알지만 오늘만 좀 봐주기로 함. 야식 뭐가 좋을까요', true, null, floor(random()*14)::int, now() - (random()*14*86400 || ' seconds')::interval),
    ('free','석사동','점심 뭐먹을지 매일 고민','회사 점심 메뉴 정하는 게 세상에서 제일 어려운 것 같아요. 매일 돌아가면서 먹을 만한 리스트 좀 만들어두고 싶은데 추천 부탁드려요 🙏','회사 점심 메뉴 정하는 게 세상에서 제일 어려운 것 같아요. 매일 돌아가면서 먹을 만한 리스트 좀 만들어두고 싶은데 추천 부탁드려요 🙏', true, null, floor(random()*14)::int, now() - (random()*14*86400 || ' seconds')::interval),
    ('free','신사우동','매운거 당기는 날','스트레스 받으면 매운 게 먹고싶어지네요. 오늘이 딱 그런 날. 얼큰하게 땀 뺄 수 있는 메뉴 추천해주실 분?','스트레스 받으면 매운 게 먹고싶어지네요. 오늘이 딱 그런 날. 얼큰하게 땀 뺄 수 있는 메뉴 추천해주실 분?', true, null, floor(random()*14)::int, now() - (random()*14*86400 || ' seconds')::interval),
    ('free','근화동','이 근처 새로 생긴 카페 가봄','근화동에 새로 카페 하나 생겼더라구요. 지나가다 들어가봤는데 분위기 괜찮았어요. 요즘 동네에 조용히 앉아있을 데 찾는 중이라 반가웠음 ☕','근화동에 새로 카페 하나 생겼더라구요. 지나가다 들어가봤는데 분위기 괜찮았어요. 요즘 동네에 조용히 앉아있을 데 찾는 중이라 반가웠음 ☕', true, null, floor(random()*14)::int, now() - (random()*14*86400 || ' seconds')::interval),
    ('free','동내면','주말 브런치 뭐가 좋을까','이번 주말엔 늦잠 자고 느긋하게 브런치 먹으려고요. 든든하면서도 부담 안 되는 메뉴 뭐 있을까요?','이번 주말엔 늦잠 자고 느긋하게 브런치 먹으려고요. 든든하면서도 부담 안 되는 메뉴 뭐 있을까요?', true, null, floor(random()*14)::int, now() - (random()*14*86400 || ' seconds')::interval),
    ('free','효자동','공지천 산책 좋네요','오랜만에 저녁에 공지천 걸었는데 바람 선선하고 진짜 좋더라구요. 요즘 산책하기 딱 좋은 계절인 듯 🙂 다들 어디 코스로 도세요?','오랜만에 저녁에 공지천 걸었는데 바람 선선하고 진짜 좋더라구요. 요즘 산책하기 딱 좋은 계절인 듯 🙂 다들 어디 코스로 도세요?', true, null, floor(random()*14)::int, now() - (random()*14*86400 || ' seconds')::interval),
    ('free','퇴계동','퇴계동 주차 어디가 편해요?','주말에 퇴계동 쪽 볼일 있어서 가는데 차 댈 데가 마땅치 않네요. 공영주차장 말고 좀 여유 있는 데 아시는 분 계실까요?','주말에 퇴계동 쪽 볼일 있어서 가는데 차 댈 데가 마땅치 않네요. 공영주차장 말고 좀 여유 있는 데 아시는 분 계실까요?', true, null, floor(random()*14)::int, now() - (random()*14*86400 || ' seconds')::interval),
    ('free','석사동','일요일에 여는 약국 있나요?','애가 갑자기 열이 나는데 일요일 낮에 문 여는 약국이 있을까요 ㅠㅠ 석사동 근처로 아시는 분 알려주시면 감사하겠습니다.','애가 갑자기 열이 나는데 일요일 낮에 문 여는 약국이 있을까요 ㅠㅠ 석사동 근처로 아시는 분 알려주시면 감사하겠습니다.', true, null, floor(random()*14)::int, now() - (random()*14*86400 || ' seconds')::interval),
    ('free','후평동','후평동에 뭐 공사하던데','후평동 큰길 쪽에 며칠째 가림막 치고 공사하던데 혹시 뭐 들어오는지 아시는 분? 지나갈 때마다 궁금하더라고요.','후평동 큰길 쪽에 며칠째 가림막 치고 공사하던데 혹시 뭐 들어오는지 아시는 분? 지나갈 때마다 궁금하더라고요.', true, null, floor(random()*14)::int, now() - (random()*14*86400 || ' seconds')::interval),
    ('free','온의동','새로 생긴 카페 가봄','온의동에 카페 하나 새로 생겼길래 들어가봤는데 분위기 조용하고 괜찮았음. 요즘 동네에 카페 자꾸 늘어나는 느낌 ㅋㅋ','온의동에 카페 하나 새로 생겼길래 들어가봤는데 분위기 조용하고 괜찮았음. 요즘 동네에 카페 자꾸 늘어나는 느낌 ㅋㅋ', true, null, floor(random()*14)::int, now() - (random()*14*86400 || ' seconds')::interval),
    ('free','근화동','밤에 좀 시끄럽지 않나요','요 며칠 근화동 쪽 밤에 좀 소란스러운 것 같은데 저만 그런가요? 창문 열어놓기가 좀 그렇네요.','요 며칠 근화동 쪽 밤에 좀 소란스러운 것 같은데 저만 그런가요? 창문 열어놓기가 좀 그렇네요.', true, null, floor(random()*14)::int, now() - (random()*14*86400 || ' seconds')::interval),
    ('free','신사우동','분리수거 요일이 어떻게 되죠?','이사 온 지 얼마 안 됐는데 신사우동 분리수거 배출 요일을 아직 잘 모르겠어요. 아파트 말고 빌라 사시는 분들 보통 어떻게 하시나요?','이사 온 지 얼마 안 됐는데 신사우동 분리수거 배출 요일을 아직 잘 모르겠어요. 아파트 말고 빌라 사시는 분들 보통 어떻게 하시나요?', true, null, floor(random()*14)::int, now() - (random()*14*86400 || ' seconds')::interval),
    ('free','약사동','동네 병원 추천','감기 기운 있어서 병원 가려는데 약사동 근처 내과 어디 괜찮은지 물어봐요. 대기 오래 안 걸리는 데면 더 좋구요 🙏','감기 기운 있어서 병원 가려는데 약사동 근처 내과 어디 괜찮은지 물어봐요. 대기 오래 안 걸리는 데면 더 좋구요 🙏', true, null, floor(random()*14)::int, now() - (random()*14*86400 || ' seconds')::interval),
    ('free','동내면','동내면 버스 배차 왜 이래요','동내면 들어오는 버스 배차가 너무 뜸한 거 아닌가요.. 한 대 놓치면 하염없이 기다려야 하니 힘드네요. 다들 어떻게 다니시는지.','동내면 들어오는 버스 배차가 너무 뜸한 거 아닌가요.. 한 대 놓치면 하염없이 기다려야 하니 힘드네요. 다들 어떻게 다니시는지.', true, null, floor(random()*14)::int, now() - (random()*14*86400 || ' seconds')::interval),
    ('staff','퇴계동','오늘따라 하루가 왜 이렇게 길지','분명 아직 세 시밖에 안 됐는데 몸은 이미 퇴근했어… 시계 자꾸 보게 되는 날 있잖아요 ㅠㅠ','분명 아직 세 시밖에 안 됐는데 몸은 이미 퇴근했어… 시계 자꾸 보게 되는 날 있잖아요 ㅠㅠ', true, null, floor(random()*14)::int, now() - (random()*14*86400 || ' seconds')::interval),
    ('staff','석사동','점심 정하는 게 제일 어려움','업무보다 ''점심 뭐 먹지''가 더 고민되는 거 나만 그래? 결국 또 어제랑 똑같은 거 먹음 ㅋㅋㅋ','업무보다 ''점심 뭐 먹지''가 더 고민되는 거 나만 그래? 결국 또 어제랑 똑같은 거 먹음 ㅋㅋㅋ', true, null, floor(random()*14)::int, now() - (random()*14*86400 || ' seconds')::interval),
    ('staff','후평동','회의만 하다 하루 다 감','오전 회의 오후 회의 그 사이 회의 준비… 정작 내 일은 언제 하냐고 😮‍💨 다들 이렇게 사는 거 맞죠?','오전 회의 오후 회의 그 사이 회의 준비… 정작 내 일은 언제 하냐고 😮‍💨 다들 이렇게 사는 거 맞죠?', true, null, floor(random()*14)::int, now() - (random()*14*86400 || ' seconds')::interval),
    ('staff','효자동','퇴근하니까 아무것도 하기 싫다','집 오면 뭐라도 해야지 다짐했는데 소파에 눕는 순간 끝. 씻는 것도 미루게 되네요.','집 오면 뭐라도 해야지 다짐했는데 소파에 눕는 순간 끝. 씻는 것도 미루게 되네요.', true, null, floor(random()*14)::int, now() - (random()*14*86400 || ' seconds')::interval),
    ('staff','온의동','월요일 아침의 그 기분','주말이 순삭됐어… 알람 끄고 딱 5분만 더 하다가 지각할 뻔. 다들 무사히 출근하셨나요','주말이 순삭됐어… 알람 끄고 딱 5분만 더 하다가 지각할 뻔. 다들 무사히 출근하셨나요', true, null, floor(random()*14)::int, now() - (random()*14*86400 || ' seconds')::interval),
    ('staff','약사동','메일 답장 하나 쓰는데 십 분 고민함','''확인했습니다''를 어떻게 정중하게 쓸지 고민하다 시간 다 감 ㅋㅋ 이게 맞나 싶다가도 또 고치고 있어','''확인했습니다''를 어떻게 정중하게 쓸지 고민하다 시간 다 감 ㅋㅋ 이게 맞나 싶다가도 또 고치고 있어', true, null, floor(random()*14)::int, now() - (random()*14*86400 || ' seconds')::interval),
    ('staff','신사우동','커피 없으면 못 버티는 하루','오후 세 시쯤 되면 카페인 안 넣으면 눈이 감겨요. 오늘 벌써 두 잔째… 이러다 잠 못 자겠지 😴','오후 세 시쯤 되면 카페인 안 넣으면 눈이 감겨요. 오늘 벌써 두 잔째… 이러다 잠 못 자겠지 😴', true, null, floor(random()*14)::int, now() - (random()*14*86400 || ' seconds')::interval),
    ('staff','근화동','금요일인데 왜 이렇게 안 가','딱 오늘만 버티면 되는데 시간이 유독 안 가네요. 이따 저녁엔 아무 생각 없이 쉬고 싶다','딱 오늘만 버티면 되는데 시간이 유독 안 가네요. 이따 저녁엔 아무 생각 없이 쉬고 싶다', true, null, floor(random()*14)::int, now() - (random()*14*86400 || ' seconds')::interval),
    ('staff','퇴계동','월요일 출근 왜 이렇게 무겁냐','주말이 순삭이라 그런가 오늘 몸이 천근만근이네요 ㅠㅠ 다들 무슨 힘으로 버티세요? 커피 한 잔으로는 택도 없다...','주말이 순삭이라 그런가 오늘 몸이 천근만근이네요 ㅠㅠ 다들 무슨 힘으로 버티세요? 커피 한 잔으로는 택도 없다...', true, null, floor(random()*14)::int, now() - (random()*14*86400 || ' seconds')::interval),
    ('staff','석사동','교대근무 하시는 분 낮잠 어떻게 주무세요','야간 끝나고 낮에 자려는데 도저히 적응이 안 돼요. 암막커튼 달아도 몸이 밤인 줄 아나봐요. 교대근무 3년차인데도 이건 도무지 익숙해지질 않네 😩 팁 있으면 좀 알려주세요.','야간 끝나고 낮에 자려는데 도저히 적응이 안 돼요. 암막커튼 달아도 몸이 밤인 줄 아나봐요. 교대근무 3년차인데도 이건 도무지 익숙해지질 않네 😩 팁 있으면 좀 알려주세요.', true, null, floor(random()*14)::int, now() - (random()*14*86400 || ' seconds')::interval),
    ('staff','후평동','요즘 텀블러 챙겨다닙니다 ㅋㅋ','매일 카페 커피 사먹으니까 한 달에 나가는 돈이 장난 아니더라고요. 그래서 텀블러에 집에서 내려서 들고 다니기 시작함. 티끌 모아 티끌인가 싶다가도 은근 뿌듯 ㅎㅎ','매일 카페 커피 사먹으니까 한 달에 나가는 돈이 장난 아니더라고요. 그래서 텀블러에 집에서 내려서 들고 다니기 시작함. 티끌 모아 티끌인가 싶다가도 은근 뿌듯 ㅎㅎ', true, null, floor(random()*14)::int, now() - (random()*14*86400 || ' seconds')::interval),
